[105] يُنظر: ((تفسير مقاتل بن سليمان)) (4/496)، ((معاني القرآن)) للفراء (3/203)، ((تفسير ابن جرير)) (23/433)، ((الوسيط)) للواحدي (4/384)، ((تفسير القرطبي)) (19/77، 78)، ((تفسير ابن كثير)) (8/268). قال ابن الجوزي: (في «البَشَرِ» قولانِ؛ أحَدُهما: أنَّه جَمعُ بَشَرةٍ، وهي جِلدةُ الإنسانِ الظَّاهِرةُ. وهذا قول مُجاهِدٍ، والفرَّاءِ، والزَّجَّاجِ. والثَّاني: أنَّهم الإنسُ مِن أهلِ النَّارِ. قاله الأخفَشُ، وابنُ قُتَيْبةَ في آخَرِينَ). ((تفسير ابن الجوزي)) (4/364). ممَّن اختار القولَ الأوَّلَ: الفَرَّاءُ، وابنُ جرير، والزَّجَّاجُ، وابنُ أبي زَمَنِين، والثعلبيُّ، ومكِّي، والواحدي، والرَّسْعَني، والنسفي، وابن جُزَي، والخازن، وجلال الدين المحلي، والعُلَيمي، وأبو السعود. يُنظر: ((معاني القرآن)) للفراء (3/203)، ((تفسير ابن جرير)) (23/433)، ((معاني القرآن وإعرابه)) للزجاج (5/247)، ((تفسير ابن أبي زمنين)) (5/57)، ((تفسير الثعلبي)) (10/73)، ((الهداية إلى بلوغ النهاية)) لمكي (12/7834)، ((الوسيط)) للواحدي (4/384)، ((تفسير الرسعني)) (8/362)، ((تفسير النسفي)) (3/565)، ((تفسير ابن جزي)) (2/429)، ((تفسير الخازن)) (4/365)، ((تفسير الجلالين)) (ص: 777)، ((تفسير العليمي)) (7/208)، ((تفسير أبي السعود)) (9/58). ونسَبَ ابنُ عطيَّةَ هذا القولَ إلى الجمهورِ، ونسَبَه الشَّوكانيُّ للأكثَرِ. يُنظر: ((تفسير ابن عطية)) (5/395)، ((تفسير الشوكاني)) (5/394). وممَّن قال بهذا القولِ مِن السَّلفِ: ابنُ عبَّاسٍ في روايةٍ عنه، ومجاهدٌ، وأبو رَزِينٍ، وزَيدُ بنُ أسْلَمَ، وقَتادةُ، والضَّحَّاكُ، وابنُ زَيدٍ. يُنظر: ((تفسير ابن جرير)) (23/434)، ((تفسير الثعلبي)) (10/74)، ((تفسير ابن كثير)) (8/268). وممَّن اختار القولَ الثَّانيَ: الأخفشُ -كما نسَبَه إليه الماوَرْديُّ وغيرُه-، وابنُ قُتَيْبةَ، والسعديُّ. يُنظر: ((تفسير الماوردي)) (6/143)، ((غريب القرآن)) لابن قتيبة (ص: 496)، ((تفسير السعدي)) (ص: 897). وقال الثعلبيُّ: (وقال الحسَنُ وابنُ كَيْسانَ: يعني: تَلوحُ لهم جهنَّمُ حتَّى يَرَوْها عِيانًا. نظيرُه: وَبُرِّزَتِ الْجَحِيمُ لِلْغَاوِينَ
[الشعراء: 91]
). ((تفسير الثعلبي)) (10/74). وقال الواحديُّ: (وقال عَطاءٌ عن ابنِ عبَّاسٍ: تَلوحُ لأهلِها مِن مسيرةِ خَمسِمئةِ عامٍ). ((البسيط)) (22/435).

[106] يُنظر: ((تفسير ابن جرير)) (23/435)، ((تفسير البغوي)) (5/177)، ((تفسير الزمخشري)) (4/650)، ((تفسير السعدي)) (ص: 897)، ((تفسير ابن عاشور)) (29/312). قال الثعلبي: (يحتَمِلُ أن يَكونوا تِسعةَ عَشَرَ مَلَكًا بأعيانِهم، وعلى هذا أكثَرُ المفَسِّرينَ). ((تفسير الثعلبي)) (10/74). قال الواحدي: (قال المفسِّرونَ: يقولُ: على النَّارِ تِسعةَ عَشَرَ مِنَ الملائكةِ، هم خَزَنتُها: مالِكٌ ومعه ثمانيةَ عَشَرَ). ((الوسيط)) (4/384). ويُنظر: ((تفسير مقاتل بن سليمان)) (4/496)، ((تفسير ابن الجوزي)) (4/364). وقال ابنُ عطيَّة: (لا خِلافَ بيْن العُلَماءِ أنَّهم خَزَنةُ جَهنَّمَ المحيطونَ بأمْرِها، الَّذين إليهم جِماعُ أمرِ زبانِيَتِها). ((تفسير ابن عطية)) (5/396). وقال القرطبي: (الصَّحيحُ -إن شاء اللهُ- أنَّ هؤلاء التِّسعةَ عَشَرَ هم الرُّؤساءُ والنُّقَباءُ، وأمَّا جُملتُهم فالعِبارةُ تَعجِزُ عنها، كما قال اللهُ تعالى: وَمَا يَعْلَمُ جُنُودَ رَبِّكَ إِلَّا هُوَ
[المدثر:31]
). ((تفسير القرطبي)) (19/80). ويُنظر: ((تفسير السمرقندي)) (3/517)، ((تفسير ابن كثير)) (8/268).

[250] يُنظر: ((تفسير ابن جرير)) (23/452)، ((تفسير ابن عطية)) (5/399)، ((تفسير الرازي)) (30/716)، ((تفسير القرطبي)) (19/88)، ((درء تعارض العقل والنقل)) لابن تيمية (3/273)، ((تفسير ابن كثير)) (8/273)، ((تفسير السعدي)) (ص: 898). قال ابن تيمية: (المرادُ به ما يُوقَنُ به من الموتِ وما بَعْدَه، باتِّفاقِ السَّلَفِ). ((الرد على الشاذلي)) (ص: 51). وقال ابن القيم: (اليقينُ هاهنا هو الموتُ، بإجماعِ أهلِ التَّفسيرِ). ((مدارج السالكين)) (1/124). ويُنظر: ((تفسير الألوسي)) (15/147). وقال الشوكاني: (هو الموتُ، كما في قَولِه تعالى: وَاعْبُدْ رَبَّكَ حَتَّى يَأْتِيَكَ الْيَقِينُ
[الحجر: 99]
). ((تفسير الشوكاني)) (5/400). ويُنظر: ((البسيط)) للواحدي (22/456).

[293] يُنظر: ((تفسير ابن جرير)) (23/460)، ((تفسير القرطبي)) (19/90)، ((تفسير ابن جزي)) (2/431)، ((تفسير ابن كثير)) (8/274). قال الواحدي: (قال المفسِّرونَ: وذلك أنَّ كُفَّارَ قُرَيشٍ قالوا لمحمَّدٍ صلَّى اللهُ عليه وسلَّم: لِيُصبِحْ عندَ رأسِ كلٍّ مِنَّا كتابٌ مَنشورٌ مِنَ اللهِ: أنَّ آلهتَنا باطِلةٌ، وأنَّ إلهَك حَقٌّ، وأنَّك رسولُه، نُؤمَرُ فيه باتِّباعِك! كقَولِه تعالى: حَتَّى تُنَزِّلَ عَلَيْنَا كِتَابًا نَقْرَؤُهُ
[الإسراء: 93]
). ((البسيط)) (22/464). وقال ابنُ جُزَي: (معنى مُنَشَّرَةً: منشورةً غَيرَ مَطويَّةٍ، أي: طريَّةً كما كُتِبَت، لم تُطْوَ بَعْدُ). ((تفسير ابن جزي)) (2/431). وقال ابنُ عاشور: (المُنَشَّرةُ: المفتوحةُ المقروءةُ، أي: لا نَكتفي بصَحيفةٍ مَطويَّةٍ لا نَعلَمُ ما كُتِب فيها). ((تفسير ابن عاشور)) (29/331).
